html:
{% set party_name = doc.party %}
{% if doc.party_type == "Customer" %}
    {% set party_info = frappe.get_doc("Customer", doc.party) %}
    {% set party_name = party_info.customer_name %}
{% elif doc.party_type == "Supplier" %}
    {% set party_info = frappe.get_doc("Supplier", doc.party) %}
    {% set party_name = party_info.supplier_name %}
{% endif %}
{% if doc.party_type == "Customer" %}
    {% set party_title = "العميل" %}
{% elif doc.party_type == "Supplier" %}
    {% set party_title = "المورد" %}
{% elif doc.party_type == "Employee" %}
    {% set party_title = "الموظف" %}
{% else %}
    {% set party_title = " " %}
{% endif %}
<style>
@media print {

    @page {
        size: A4;
         margin: 1cm 0.8cm 2.54cm 0.8cm;
    }
    html, body {
        margin: 0 !important;
        padding: 0 !important;
    }

    .print-format {
        margin-top: 0 !important;
        padding-top: 0 !important;
    }

}
 @page {
        size: A4;
        margin: 0;
    }

    html, body {
        margin: 0 !important;
        padding: 0 !important;
    }

    .print-format {
        margin-top: 0 !important;
        padding-top: 0 !important;
    }


/* إزالة أي فراغ فوق الهيدر */
.letter-head,
.letter-head + * {
    margin-top: 0 !important;
    padding-top: 0 !important;
}
    thead { 
        display: table-header-group; 
    }

    .no-print {
        display: none !important;
    }
}

body {
    font-family: "Times New Roman", serif;
    direction: rtl;
}

.report-title {
    text-align: center;
    font-size: 22px;
    font-weight: bold;
    margin: 0;
}

.party-name {
    text-align: center;
    font-size: 18px;
    font-weight: bold;
    margin-bottom: 5px;
}

.info-box {
    width: 98%;
    margin-left: auto;
    margin-right: auto;
    border: 1px solid #999;
    padding: 8px;
    margin-bottom: 10px;
    font-size: 15px;
}

.table-main {
    width: 98%;
    margin-left: auto;
    margin-right: auto;
    border-collapse: collapse;
    font-size: 13px;
    table-layout: fixed;
}

.table-main th {
    background-color: #2c3e50 !important;
    font-weight: bold;
    color: white;
    border: 1px solid #bdc3c7;
    padding: 0.1px 0.1px;
    text-align: center !important;
    font-size: 14px;
}

.table-main td {
    padding: 0.1px 0.1px;
    border: 1px solid #bdc3c7;
    word-wrap: break-word;
    vertical-align: middle !important;
    font-size: 11px;
}
.number {
    text-align: left;
    direction: ltr;
    font-weight: bold;
}

.debit {
    color: #1e7e34;
}

.credit {
    color: #c82333;
}

.balance {
    color: #0b5394;
}

.signatures {
    width: 90%;
    margin-left: auto;
    margin-right: auto;
    margin-top: 50px;
    display: flex;
    justify-content: space-between;
    text-align: center;
    font-size: 16px;
}

.sign-line {
    border-top: 1px solid #000;
    width: 70%;
    margin: 40px auto 5px auto;
}
</style>

<div>

    <!-- ================= LETTER HEAD المختار من المستخدم ================= -->
    {% if letter_head %}
        <div style="margin:0; padding:0;">
            {{ letter_head }}
        </div>
    {% endif %}

    <!-- ================= TITLE ================= -->
    <div class="report-title">كشف حساب  {{ party_title }} </div>
    <div class="party-name">{{ party_name }} </div>

    <!-- ================= INFO ================= -->
    <div class="info-box">
        {{party_title}}: {{ party_name       }}         |  
        الفترة: من {{ doc.from_date }} إلى {{ doc.to_date }}   |    
        العملة: {{ doc.currency or "SAR" }}
    </div>

    <!-- ================= TABLE ================= -->
    <table class="table-main">
        <thead>
            <tr>
                <th style="width:10%;margin:0; padding:0;">التاريخ</th>
                <th style="width:10%;margin:0; padding:0;">نوع المستند</th>
                <th style="width:17%;margin:0; padding:0;">رقم المستند</th>
                <th style="width:30%;margin:0; padding:0;">البيان</th>
                <th style="width: 10%; text-align: left; direction: ltr !important;">مدين</th>
                <th style="width: 10%; text-align: left; direction: ltr !important;">دائن</th>
                <th style="width: 11%; text-align: left; direction:  ltr !important;">الرصيد</th>
            </tr>
        </thead>

        <tbody>

        {% for row in doc.entries %}

            <tr style="
                {% if loop.last %}
                    background-color: #e5e0e0 !important;
                    color: #111111 !important;
                    font-weight:bold;
                {% elif loop.index % 2 == 0 %}
                    background:#f2f2f2;
                {% endif %}
            ">

                <td style="text-align:center ;margin:0 !important; padding:0 !important;">{{ row.date or "" }}</td>
                <td style="text-align:center;margin:0 !important; padding:0 !important;">{{ row.voucher_type }}</td>
                <td style="text-align:center;margin:0 !important; padding:0 !important;">{{ row.voucher_no }}</td>
                <td>{{ row.remarks or "" }}</td>

                <td class="number"
                    {% if not loop.last %} style="color:#1e7e34; text-align: right;" {% endif %}>
                    {{ "{:,.2f}".format(row.debit or 0) }}
                </td>

                <td class="number"
                    {% if not loop.last %} style="color:#c82333; text-align: right;" {% endif %}>
                    {{ "{:,.2f}".format(row.credit or 0) }}
                </td>

                <td class="number"
                    {% if not loop.last %}
                        style="
                        {% if row.running_balance < 0 %}
                            color:#c82333;
                        {% else %}
                            color:#0b5394;
                        {% endif %}
                         text-align: right;"
                    {% endif %}>
                    {{ "{:,.2f}".format(row.running_balance or 0) }}
                </td>

            </tr>

        {% endfor %}

        </tbody>
    </table>
{% if doc.aging %}

{% set a = doc.aging %}

{% set v0  = (a.split("(-30):")[1].split("(30+)")[0]).strip() if "(-30):" in a else "0.00" %}
{% set v30 = (a.split("(30+):")[1].split("(60+)")[0]).strip() if "(30+):" in a else "0.00" %}
{% set v60 = (a.split("(60+):")[1].split("(90+)")[0]).strip() if "(60+):" in a else "0.00" %}
{% set v90 = (a.split("(90+):")[1].split("(120+)")[0]).strip() if "(90+):" in a else "0.00" %}
{% set v120 = (a.split("(120+):")[1].split("Total")[0]).strip() if "(120+):" in a else "0.00" %}
{% set vtotal = (a.split("Total:")[1]).strip() if "Total:" in a else "0.00" %}

<div style="width:100%; margin-top:10px;">

    <table style="width:100%; border-collapse:collapse; font-size:10px; direction:rtl; text-align:center;">

        <tr>
            <td style="padding:1px;">
                <strong>(0-30): {{ v0 }}</strong>
            </td>

            <td style=" padding:1px;">
                <strong>(30-60): {{ v30 }}</strong>
            </td>

            <td style=" padding:1px;">
                <strong>(60-90): {{ v60 }}</strong>
            </td>

            <td style=" padding:1px;">
                <strong>(90-120): {{ v90 }}</strong>
            </td>

            <td style=" padding:1px;">
                <strong>(>120): {{ v120 }}</strong>
            </td>

            <td style=" padding:1px;">
                <strong>Total: {{ vtotal }}</strong>
            </td>
        </tr>

    </table>

</div>

{% endif %}
    <!-- ================= SIGNATURES ================= -->
    <div class="signatures">
        <div>
            <div class="sign-line"></div>
            المحاسب
        </div>
        <div>
            <div class="sign-line"></div>
            المراجع
        </div>
        <div>
            <div class="sign-line"></div>
            المدير العام
        </div>
    </div>

</div>
